SELECT eiaid_weights.eiaid AS eiaid, sum(1) AS sample_count, sum(baseline.weight * eiaid_weights.weight) AS units_count, sum(baseline."out.site_energy.net.energy_consumption" * baseline.weight * eiaid_weights.weight) AS "site_energy.net.energy_consumption", sum(baseline."out.site_energy.total.energy_consumption" * baseline.weight * eiaid_weights.weight) AS "site_energy.total.energy_consumption" FROM (SELECT * FROM resstock_2024_amy2018_release_2_metadata WHERE resstock_2024_amy2018_release_2_metadata.upgrade = 0) AS baseline JOIN eiaid_weights ON baseline."in.county" = eiaid_weights.gisjoin WHERE baseline.applicability = true GROUP BY 1 ORDER BY 1